import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

// Place helper components here if needed
const TOTAL_STEPS = 4;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && validateEmail(formData.email);
  }, [formData.name, formData.email]);

  const handleNext = () => {
    if (step < TOTAL_STEPS) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  const progress = (step / TOTAL_STEPS) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Row justify="between" align="center">
          <Heading level={2}>Feedback Survey</Heading>
          <Text variant="label">Step {step} of {TOTAL_STEPS}</Text>
        </Row>
        <Progress value={progress} />

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Details</Heading>
              <Input
                label="Name"
                value={formData.name}
                onChange={(val) => {
                  setFormData({ ...formData, name: val });
                  setErrors({ ...errors, name: val.trim() === '' ? 'Name is required' : '' });
                }}
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(val) => {
                  setFormData({ ...formData, email: val });
                  setErrors({ ...errors, email: validateEmail(val) ? '' : 'Invalid email format' });
                }}
                error={errors.email}
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                options={(props.satisfactionLabels || []).map((label) => ({ label, value: label }))}
                value={(props.satisfactionLabels || [])[formData.satisfaction - 1] || ''}
                onChange={(val) => {
                  const idx = (props.satisfactionLabels || []).indexOf(val);
                  if (idx !== -1) setFormData({ ...formData, satisfaction: idx + 1 });
                }}
              />
              <Text variant="caption">Selected: {(props.satisfactionLabels || [])[formData.satisfaction - 1] || 'None'}</Text>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature Interests</Heading>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={formData.features.includes(feature)}
                  onChange={(checked) => {
                    setFormData({
                      ...formData,
                      features: checked
                        ? [...formData.features, feature]
                        : formData.features.filter((f) => f !== feature),
                    });
                  }}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review & Submit</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {(props.satisfactionLabels || [])[formData.satisfaction - 1] || 'N/A'}</Text>
              <Text>Features: {formData.features.join(', ') || 'None'}</Text>
              <Text>Comments: {formData.comments || 'None'}</Text>
              <TextArea
                label="Anything else?"
                value={formData.comments}
                onChange={(val) => setFormData({ ...formData, comments: val })}
                maxLength={500}
                showCount
                rows={4}
              />
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-2)" justify="end">
          {step > 1 && (
            <Button as={Clickable} variant="secondary" onClick={handleBack}>Back</Button>
          )}
          {step < TOTAL_STEPS ? (
            <Button
              as={Clickable}
              variant="primary"
              onClick={handleNext}
              disabled={step === 1 && !isStep1Valid}
            >
              Next
            </Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleSubmit}>Submit</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

