        <Text variant="body" as={Clickable} onDoubleClick={() => onEdit(task)}>{task.title}</Text>
        {task.dueDate && <Text variant="caption">Due: {task.dueDate}</Text>}
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Badge variant="default" size="sm" style={{ backgroundColor: PRIORITY_COLORS[task.priority as keyof typeof PRIORITY_COLORS] }}>{task.priority}</Badge>
          {task.assignee && <Avatar name={task.assignee} size="xs" />}
          <Spacer size="flex" />
          <Button size="xs" variant="ghost" as={Clickable} onClick={() => onEdit(task)}><Icon name="edit-2" size={16} /></Button>
          <Dropdown
            trigger={<Button size="xs" variant="ghost" as={Clickable}><Icon name="more-vertical" size={16} /></Button>}
            options={[
              { value: 'todo', label: 'Move to To Do' },
              { value: 'in-progress', label: 'Move to In Progress' },
              { value: 'done', label: 'Move to Done' },
            ]}
            onChange={(col) => moveTask(task.id, col)}
          />
        </Row>
      </Stack>
    </Card>
  );
}

function AddTaskForm({ onAdd, columnId, onClose }: { onAdd: (t: any) => void; columnId: string; onClose: () => void }) {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState('medium');
  return (
    <Card padding="var(--ggui-spacing-3)" shadow="md">
      <Stack gap="var(--ggui-spacing-2)">
        <Input label="Task Title" value={title} onChange={setTitle} />
        <Select label="Priority" value={priority} onChange={setPriority} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
        <Row gap="var(--ggui-spacing-2)">
          <Button size="sm" as={Clickable} onClick={() => onAdd({ title, priority, column: columnId })}>Save</Button>
          <Button size="sm" variant="ghost" as={Clickable} onClick={onClose}>Cancel</Button>
        </Row>
      </Stack>
    </Card>
  );
}




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [editingTask, setEditingTask] = useState<any>(null);

  useEffect(() => {
    if (taskChanged.latest?.action === 'create' && taskChanged.latest.task) {
        setTasks(prev => [...prev, taskChanged.latest!.task]);
    } else if (taskChanged.latest?.action === 'move' && taskChanged.latest.task) {
        setTasks(prev => prev.map(t => t.id === taskChanged.latest!.task!.id ? taskChanged.latest!.task! : t));
    }
  }, [taskChanged.latest]);

  const moveTask = useCallback((taskId: string, column: string) => {
    taskUpdate({ action: 'move', taskId, data: { column } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column } : t));
  }, [taskUpdate]);

  const updateTask = useCallback((taskId: string, data: any) => {
    taskUpdate({ action: 'edit', taskId, data });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...data } : t));
    setEditingTask(null);
  }, [taskUpdate]);

  const addTask = useCallback((data: any) => {
    const newTask = { id: Math.random().toString(36), ...data };
    taskUpdate({ action: 'create', taskId: newTask.id, data: { ...data } });
    setTasks(prev => [...prev, newTask]);
    setAddingTo(null);
  }, [taskUpdate]);


  const completedCount = useMemo(() => tasks.filter(t => t.column === 'done').length, [tasks]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row align="center" justify="between">
          <Heading level={2}>Task Board</Heading>
          <Badge variant="primary">Total: {tasks.length} | Done: {completedCount}</Badge>
        </Row>
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map(col => (
            <Stack key={col.id} gap="var(--ggui-spacing-3)" style={{ flex: 1 }}>
              <Heading level={4}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>
              {tasks.filter(t => t.column === col.id).map(t => (
                  <TaskCard key={t.id} task={t} moveTask={moveTask} onEdit={setEditingTask} />
              ))}
              {addingTo === col.id ? (
                  <AddTaskForm onAdd={addTask} columnId={col.id!} onClose={() => setAddingTo(null)} />
              ) : (
                  <Button variant="ghost" size="sm" as={Clickable} onClick={() => setAddingTo(col.id || null)}>+ Add Task</Button>
              )}
            </Stack>
          ))}
        </Row>
      </Stack>
      {editingTask && (
      <Modal open={!!editingTask} onClose={() => setEditingTask(null)} title="Edit Task">
          <Box style={{ padding: 'var(--ggui-spacing-4)' }}>
            <Stack gap="var(--ggui-spacing-3)">
              <Input label="Title" value={editingTask?.title || ''} onChange={(val: string) => setEditingTask({...editingTask, title: val})} />
              <Select label="Priority" value={editingTask?.priority || 'medium'} onChange={(val: string) => setEditingTask({...editingTask, priority: val})} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
              <Button as={Clickable} onClick={() => updateTask(editingTask.id, editingTask)}>Save Changes</Button>
            </Stack>
          </Box>
        </Modal>

      )}
    </Container>
  );
}

