                <Row gap="var(--ggui-spacing-2)">
                  {(props.avatarOptions || []).map((e) => (
                    <Box key={e} as={Clickable} onClick={() => setAvatar(e)} padding="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-md)" background={avatar === e ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}>
                      <Text>{e}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Preferences</Heading>
              <Select label="Role" value={role} onChange={setRole} options={(props.roleOptions || []).map((r) => ({ value: r, label: r }))} placeholder="Select your role" />
              <Row align="center" justify="between">
                <Text>Email Notifications</Text>
                <Toggle checked={emailNotifications} onChange={setEmailNotifications} />
              </Row>
              <Row align="center" justify="between">
                <Text>Dark Mode</Text>
                <Toggle checked={theme === 'dark'} onChange={(checked) => setTheme(checked ? 'dark' : 'light')} />
              </Row>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review & Confirm</Heading>
              <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><strong>Name:</strong> {name}</Text>
                  <Text><strong>Email:</strong> {email}</Text>
                  <Text><strong>Role:</strong> {role}</Text>
                  <Text><strong>Avatar:</strong> {avatar}</Text>
                  <Text><strong>Notifications:</strong> {emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  <Text><strong>Theme:</strong> {theme}</Text>
                </Stack>
              </Box>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={step === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
